# ── TWO COLUMNS ─────────────────────────────────────────────────
left_col, right_col = st.columns([1.15, 0.85])

# RIGHT — X-ray viewer (unchanged)
with right_col:
    components.html(xray_viewer_html(XRAY_B64), height=660, scrolling=False)

# LEFT — full dark UI
with left_col:

    # Condition cards
    st.markdown("""
    <div class="cond-row">
      <div class="cond-box cn">
        <div class="ct cn">NORMAL</div>
        <div class="cd">Healthy bone density. No signs of bone loss.</div>
      </div>
      <div class="cond-box co">
        <div class="ct co">OSTEOPENIA</div>
        <div class="cd">Mildly low density. Medical review advised.</div>
      </div>
      <div class="cond-box cr">
        <div class="ct cr">OSTEOPOROSIS</div>
        <div class="cd">Very low density. Immediate consultation needed.</div>
      </div>
    </div>
    """, unsafe_allow_html=True)

    # Upload
    st.markdown('<div class="upload-card"><div class="upload-hdr">// Upload Knee X-Ray</div>', unsafe_allow_html=True)
    uploaded_file = st.file_uploader(
        "Drag and drop or click to browse",
        type=["jpg", "jpeg", "png"],
        label_visibility="collapsed"
    )
    st.markdown('</div>', unsafe_allow_html=True)

    if uploaded_file is not None:
        image = Image.open(uploaded_file).convert("RGB")
        st.image(image, caption="Uploaded X-Ray", use_column_width=True)

        img_array = np.expand_dims(
            np.array(image.resize((224, 224)), dtype=np.float32), axis=0
        )

        with st.spinner("Analyzing bone density..."):
            prediction = model.predict(img_array, verbose=0)

        predicted_index = int(np.argmax(prediction[0]))
        predicted_class  = class_names[predicted_index]
        confidence        = float(np.max(prediction[0]))
        css_class         = predicted_class.lower()
        now               = datetime.datetime.now().strftime("%H:%M:%S")

        # Save to history
        st.session_state.scan_count += 1
        st.session_state.history.insert(0, {
            "idx":   st.session_state.scan_count,
            "cls":   predicted_class,
            "conf":  confidence,
            "time":  now
        })
        if len(st.session_state.history) > 5:
            st.session_state.history = st.session_state.history[:5]

        # Result card
        st.markdown(f"""
        <div class="result-card">
          <div class="result-tag">// Diagnosis Result</div>
          <div class="pred-label {css_class}">{predicted_class.upper()}</div>
          <div class="conf-pill">CONFIDENCE: {confidence:.2%}</div>
        </div>
        """, unsafe_allow_html=True)

        # Clinical message
        if predicted_class == "Normal":
            st.success("The knee appears healthy with normal bone density.")
        elif predicted_class == "Osteopenia":
            st.warning("Low bone density detected. Medical consultation is recommended.")
        else:
            st.error("Severely low bone density. Please consult a doctor immediately.")

        # Probability bars
        colors = ["fill-n", "fill-op", "fill-os"]
        st.markdown('<div class="risk-bar-wrap"><div class="risk-title">// Class Probabilities</div>', unsafe_allow_html=True)
        for cls, prob, color in zip(class_names, prediction[0], colors):
            p   = float(prob)
            pct = round(p * 100, 1)
            st.markdown(f"""
            <div class="risk-row">
              <div class="risk-name">{cls.upper()}</div>
              <div class="risk-bg"><div class="risk-fill {color}" style="width:{pct}%"></div></div>
              <div class="risk-pct">{pct}%</div>
            </div>""", unsafe_allow_html=True)
        st.markdown('</div>', unsafe_allow_html=True)

        # Download report
        report_lines = [
            "KneeAI — Bone Density Analysis Report",
            "=" * 40,
            f"Date/Time  : {datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')}",
            f"Diagnosis  : {predicted_class}",
            f"Confidence : {confidence:.2%}",
            "",
            "Class Probabilities:",
        ]
        for cls, prob in zip(class_names, prediction[0]):
            report_lines.append(f"  {cls:<14}: {float(prob)*100:.1f}%")
        report_lines += [
            "",
            "DISCLAIMER: Educational purposes only.",
            "Always consult a qualified medical professional.",
        ]
        report_text = "\n".join(report_lines)

        st.download_button(
            label="⬇  DOWNLOAD REPORT (.txt)",
            data=report_text,
            file_name=f"kneeai_report_{now.replace(':','')}.txt",
            mime="text/plain",
            use_container_width=True
        )

        # Disclaimer
        st.markdown("""
        <div class="disclaimer">
          ⚠ This tool is for <strong>educational purposes only</strong> and does not
          replace professional medical advice. Always consult a qualified
          medical professional for diagnosis and treatment.
        </div>""", unsafe_allow_html=True)

    # Scan history (always visible)
    if st.session_state.history:
        st.markdown('<div class="hist-wrap"><div class="hist-title">// Scan History</div>', unsafe_allow_html=True)
        for h in st.session_state.history:
            css = h["cls"].lower()
            st.markdown(f"""
            <div class="hist-row">
              <span class="hist-idx">#{h["idx"]}</span>
              <span class="hist-cls {css}">{h["cls"].upper()}</span>
              <span class="hist-conf">{h["conf"]:.1%}</span>
              <span class="hist-time">{h["time"]}</span>
            </div>""", unsafe_allow_html=True)
        st.markdown('</div>', unsafe_allow_html=True)